13	const PROCESSING_FEE = 5;
14	const FIRST_INSURANCE_RATE = 0.1;
15	const BASE_PREMIUM: Record<string, number> = { sword: 100, staff: 80, potion: 40, rune: 25, moonstone: 25 };
16	const DEFAULT_BASE_PREMIUM = 60;
17	
18	const CURSE_SURCHARGE_RATE = 0.5;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
21	const BLOCK_SIZE = 3;
22	const BLOCK_PREMIUM = 60;
23	
24	function basePremiumForType(type: string): number {
25	  return BASE_PREMIUM[type] ?? DEFAULT_BASE_PREMIUM;
26	}
27	
28	function countByType(items: Item[]): Record<string, number> {
29	  const counts: Record<string, number> = {};
30	  for (const item of items) {
31	    counts[item.type] = (counts[item.type] ?? 0) + 1;
32	  }
33	  return counts;
34	}
35	
36	function itemGroupPremium(type: string, count: number): number {
37	  if (count === BLOCK_SIZE) {
38	    return BLOCK_PREMIUM;
39	  }
40	  return count * basePremiumForType(type);
41	}
42	
43	export function quote(policy: Policy) {
44	  const counts = countByType(policy.items);
45	
46	  let basePremium = 0;
47	  for (const [type, count] of Object.entries(counts)) {
48	    basePremium += itemGroupPremium(type, count);
49	  }
50	
51	  let curseSurcharge = 0;
52	  let highEnchantmentSurcharge = 0;
53	  for (const item of policy.items) {
54	    if (item.cursed) {
55	      curseSurcharge += basePremiumForType(item.type) * CURSE_SURCHARGE_RATE;
56	    }
57	    if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
58	      highEnchantmentSurcharge += basePremiumForType(item.type) * HIGH_ENCHANTMENT_SURCHARGE_RATE;
59	    }
60	  }
61	
62	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
63	  const premium = Math.ceil(basePremium + curseSurcharge + highEnchantmentSurcharge + firstInsuranceSurcharge + PROCESSING_FEE);
64	  return { premium };
65	}
66	
67	export function claim() {
68	  return undefined;
